import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    vals, counts = np.unique(grid[grid != 0], return_counts=True)
    if len(vals) == 0:
        return grid.copy()

    # Find the unique nonzero color used by exactly one connected nonzero block
    # by detecting maximal rectangular tile regions separated by zero bands.
    h, w = grid.shape

    def zero_runs(arr):
        runs = []
        i = 0
        n = len(arr)
        while i < n:
            if arr[i] == 0:
                j = i
                while j < n and arr[j] == 0:
                    j += 1
                runs.append((i, j))
                i = j
            else:
                i += 1
        return runs

    row_zero = np.all(grid == 0, axis=1)
    col_zero = np.all(grid == 0, axis=0)

    row_runs = zero_runs(row_zero.astype(int))
    col_runs = zero_runs(col_zero.astype(int))

    row_bounds = []
    start = 0
    for a, b in row_runs:
        if start < a:
            row_bounds.append((start, a))
        start = b
    if start < h:
        row_bounds.append((start, h))

    col_bounds = []
    start = 0
    for a, b in col_runs:
        if start < a:
            col_bounds.append((start, a))
        start = b
    if start < w:
        col_bounds.append((start, w))

    # Choose the tile whose nonzero cells are all the same color and that color is unique globally.
    best = None
    for r0, r1 in row_bounds:
        for c0, c1 in col_bounds:
            tile = grid[r0:r1, c0:c1]
            nz = tile[tile != 0]
            if nz.size == 0:
                continue
            u = np.unique(nz)
            if len(u) == 1:
                color = int(u[0])
                if np.sum(grid == color) == nz.size:
                    best = tile
                    break
        if best is not None:
            break

    if best is None:
        # Fallback: use the color with smallest count among nonzero colors
        color = int(vals[np.argmin(counts)])
        positions = np.argwhere(grid == color)
        r0, c0 = positions.min(axis=0)
        r1, c1 = positions.max(axis=0) + 1
        best = grid[r0:r1, c0:c1]

    out = (best != 0).astype(int) * 3
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape

    def row_period(row):
        for p in range(1, w + 1):
            ok = True
            for j in range(w):
                v = row[j]
                if v != 0 and v != row[j % p]:
                    ok = False
                    break
            if ok:
                return p
        return w

    def col_period(col):
        for p in range(1, h + 1):
            ok = True
            for i in range(h):
                v = col[i]
                if v != 0 and v != col[i % p]:
                    ok = False
                    break
            if ok:
                return p
        return h

    rp = min(row_period(g[i]) for i in range(h))
    cp = min(col_period(g[:, j]) for j in range(w))

    tile = np.zeros((cp, rp), dtype=g.dtype)
    for i in range(h):
        for j in range(w):
            v = g[i, j]
            if v != 0:
                tile[i % cp, j % rp] = v

    out = np.empty_like(g)
    for i in range(h):
        for j in range(w):
            out[i, j] = tile[i % cp, j % rp]
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    seeds = [(r, c, grid[r, c]) for r in range(h) for c in range(w) if grid[r, c] != 0]
    for r, c, color in seeds:
        for cc in range(w):
            if grid[r, cc] == 0:
                grid[r, cc] = color
        for rr in range(h):
            if grid[rr, c] == 0:
                grid[rr, c] = color
    return grid

