def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    for r in range(grid.shape[0]):
        nz = np.nonzero(grid[r])[0]
        if len(nz) == 2:
            c1, c2 = nz
            if grid[r, c1] == grid[r, c2]:
                grid[r, c1:c2 + 1] = grid[r, c1]
    return grid

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    vals, counts = np.unique(input_grid, return_counts=True)
    color_counts = {int(v): int(c) for v, c in zip(vals, counts) if v != 0}

    c1 = color_counts.get(1, 0)
    c2 = color_counts.get(2, 0)
    c8 = color_counts.get(8, 0)

    # Determine the two non-black colors present
    colors = [c for c in [1, 2, 8] if color_counts.get(c, 0) > 0]
    if len(colors) == 0:
        return np.array([[0]], dtype=int)
    if len(colors) == 1:
        return np.array([[colors[0]]], dtype=int)

    # Compare the two colored counts; if tied, output black
    a, b = colors[0], colors[1]
    ca, cb = color_counts.get(a, 0), color_counts.get(b, 0)
    if ca > cb:
        return np.array([[a]], dtype=int)
    if cb > ca:
        return np.array([[b]], dtype=int)
    return np.array([[0]], dtype=int)

