import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    rows, cols = grid.shape
    teal_rows = [r for r in range(rows) if np.any(grid[r] == 8)]
    if not teal_rows:
        return grid

    top = teal_rows[0]
    bottom = teal_rows[-1]

    for r in range(top, bottom + 1):
        cols8 = np.where(grid[r] == 8)[0]
        if len(cols8) == 2:
            c1, c2 = cols8
            if c1 > c2:
                c1, c2 = c2, c1
            grid[r, c1 + 1:c2] = 3
        elif len(cols8) == 1:
            c = cols8[0]
            lower_rows = [rr for rr in teal_rows if rr > r and grid[rr, c] == 8]
            if lower_rows:
                rr = lower_rows[0]
                grid[r + 1:rr, c] = 3

    return grid

