def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    divider_rows = np.where(np.all(grid == 4, axis=1))[0]
    if len(divider_rows) == 0:
        return grid.copy()
    d = divider_rows[0]
    top = grid[:d]
    bottom = grid[d + 1:]

    fg = 2 if np.any(grid == 2) else None
    if fg is None:
        vals, counts = np.unique(grid[grid != 0], return_counts=True)
        fg = vals[np.argmax(counts)] if len(vals) else 0

    top = (top == fg).astype(int)
    bottom = (bottom == fg).astype(int)

    h = min(top.shape[0], bottom.shape[0], 6)
    w = min(top.shape[1], bottom.shape[1], 5)

    out = np.zeros((h, w), dtype=int)
    for r in range(h):
        for c in range(w):
            if top[r, c] != bottom[r, c]:
                out[r, c] = 3
            else:
                out[r, c] = 0
    return out

