import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    first = grid[0].copy()
    out = np.zeros_like(grid)

    for r in range(h):
        if r % 2 == 0:
            out[r] = first
        else:
            row = np.zeros(w, dtype=grid.dtype)
            for c in range(w):
                if first[c] != 0:
                    if c - 1 >= 0:
                        row[c - 1] = first[c]
                    if c + 1 < w:
                        row[c + 1] = first[c]
            out[r] = row
    return out

