import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    h, w = grid.shape

    def find_tile_size(arr):
        # Try all divisors; choose the largest size that makes each tile's top-left
        # corners consistent with the mosaic labels.
        divisors_h = [d for d in range(1, h + 1) if h % d == 0]
        divisors_w = [d for d in range(1, w + 1) if w % d == 0]
        for th in sorted(divisors_h, reverse=True):
            for tw in sorted(divisors_w, reverse=True):
                if th != tw:
                    continue
                s = th
                ok = True
                for r in range(0, h, s):
                    for c in range(0, w, s):
                        label = arr[r, c]
                        # tile should be mostly uniform with label at top-left
                        # and the label should appear in the tile
                        if label not in arr[r:r+s, c:c+s]:
                            ok = False
                            break
                    if not ok:
                        break
                if ok:
                    return s
        return 1

    s = find_tile_size(grid)
    out_h, out_w = h // s, w // s
    out = np.zeros((out_h, out_w), dtype=int)
    for i in range(out_h):
        for j in range(out_w):
            out[i, j] = int(grid[i * s, j * s])
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    visited = np.zeros((h, w), dtype=bool)

    for r in range(h):
        for c in range(w):
            if grid[r, c] == 4 and not visited[r, c]:
                stack = [(r, c)]
                visited[r, c] = True
                cells = []
                while stack:
                    x, y = stack.pop()
                    cells.append((x, y))
                    for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nx, ny = x + dx, y + dy
                        if 0 <= nx < h and 0 <= ny < w and grid[nx, ny] == 4 and not visited[nx, ny]:
                            visited[nx, ny] = True
                            stack.append((nx, ny))

                rows = [x for x, y in cells]
                cols = [y for x, y in cells]
                r0, r1 = min(rows), max(rows)
                c0, c1 = min(cols), max(cols)

                for i in range(r0, r1 + 1):
                    for j in range(c0, c1 + 1):
                        if grid[i, j] == 0:
                            grid[i, j] = 7
    return grid

