def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    out = np.zeros_like(grid)
    ys, xs = np.where(grid != 0)
    if len(ys) == 0:
        return out
    y, x = int(ys[0]), int(xs[0])
    c = int(grid[y, x])
    h, w = grid.shape
    for i in range(h):
        for j in range(w):
            if abs(i - y) == abs(j - x):
                out[i, j] = c
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    # Find gray frame bounding box
    gray = 5
    rows = np.where(np.any(grid == gray, axis=1))[0]
    cols = np.where(np.any(grid == gray, axis=0))[0]
    if len(rows) == 0 or len(cols) == 0:
        return grid

    r0, r1 = rows[0], rows[-1]
    c0, c1 = cols[0], cols[-1]

    # Extract the "inside/adjacent" shape in the upper-left region relative to the frame
    # and the matching shape in the lower-right region outside the frame.
    # We identify connected components of non-gray, non-zero cells.
    visited = np.zeros((h, w), dtype=bool)
    comps = []

    def neighbors(r, c):
        if r > 0: yield r - 1, c
        if r + 1 < h: yield r + 1, c
        if c > 0: yield r, c - 1
        if c + 1 < w: yield r, c + 1

    for i in range(h):
        for j in range(w):
            if grid[i, j] != 0 and grid[i, j] != gray and not visited[i, j]:
                color = grid[i, j]
                stack = [(i, j)]
                visited[i, j] = True
                cells = []
                while stack:
                    r, c = stack.pop()
                    cells.append((r, c))
                    for nr, nc in neighbors(r, c):
                        if not visited[nr, nc] and grid[nr, nc] == color:
                            visited[nr, nc] = True
                            stack.append((nr, nc))
                rs = [p[0] for p in cells]
                cs = [p[1] for p in cells]
                comps.append({
                    "color": color,
                    "cells": cells,
                    "bbox": (min(rs), min(cs), max(rs), max(cs)),
                    "shape": sorted((r - min(rs), c - min(cs)) for r, c in cells),
                })

    # Choose the component in the upper-left area as the template,
    # and recolor matching component in lower-right area to gray.
    template = None
    target = None

    for comp in comps:
        minr, minc, maxr, maxc = comp["bbox"]
        if maxr <= r1 and maxc <= c1:
            if template is None or (minr < template["bbox"][0] and minc < template["bbox"][1]):
                template = comp

    if template is None:
        return grid

    for comp in comps:
        if comp is template:
            continue
        minr, minc, maxr, maxc = comp["bbox"]
        if minr >= r1 and minc >= c1 and comp["shape"] == template["shape"]:
            target = comp
            break

    if target is not None:
        for r, c in target["cells"]:
            grid[r, c] = gray

    return grid

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    k = len(np.unique(input_grid))
    out = np.zeros((3, 3), dtype=int)

    if k == 1:
        out[0, :] = 5
    elif k == 2:
        np.fill_diagonal(out, 5)
    elif k == 3:
        out[np.arange(3), np.arange(2, -1, -1)] = 5
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    nz = np.argwhere(grid != 0)
    if nz.size == 0:
        return grid.copy()
    r0, c0 = nz.min(axis=0)
    r1, c1 = nz.max(axis=0) + 1
    rect = grid[r0:r1, c0:c1]
    return np.flipud(np.fliplr(rect))

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    # Find the framed tile: a 4x4 interior enclosed by a 1-cell-thick gray border.
    frame_color = 5
    stamp_color = None
    stamp_pattern = None

    for r in range(h - 6):
        for c in range(w - 6):
            block = grid[r:r+7, c:c+7]
            if np.all(block[0, :] == frame_color) and np.all(block[6, :] == frame_color) and \
               np.all(block[:, 0] == frame_color) and np.all(block[:, 6] == frame_color):
                interior = block[1:6, 1:6]
                colors = interior[interior != 0]
                if colors.size == 0:
                    continue
                unique_colors = np.unique(colors)
                if unique_colors.size == 1:
                    stamp_color = int(unique_colors[0])
                    stamp_pattern = (interior == stamp_color).astype(np.uint8)
                    break
        if stamp_pattern is not None:
            break

    if stamp_pattern is None:
        return grid

    # Recolor matching 4x4 tiles elsewhere using the stamp color.
    for r in range(h - 3):
        for c in range(w - 3):
            tile = grid[r:r+4, c:c+4]
            if np.array_equal((tile == stamp_color).astype(np.uint8), stamp_pattern):
                grid[r:r+4, c:c+4] = np.where(tile != 0, stamp_color, tile)

    return grid

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    rows, cols = grid.shape

    nonzero_rows = np.where(np.any(grid != 0, axis=1))[0]
    nonzero_cols = np.where(np.any(grid != 0, axis=0))[0]

    if len(nonzero_rows) == 0 or len(nonzero_cols) == 0:
        return np.zeros((0, 0), dtype=int)

    # Find contiguous groups of nonzero rows/cols
    def groups(indices):
        gs = []
        start = indices[0]
        prev = indices[0]
        for x in indices[1:]:
            if x == prev + 1:
                prev = x
            else:
                gs.append((start, prev))
                start = prev = x
        gs.append((start, prev))
        return gs

    row_groups = groups(nonzero_rows)
    col_groups = groups(nonzero_cols)

    out = np.zeros((len(row_groups), len(col_groups)), dtype=int)

    for i, (r0, r1) in enumerate(row_groups):
        for j, (c0, c1) in enumerate(col_groups):
            block = grid[r0:r1 + 1, c0:c1 + 1]
            vals = block[block != 0]
            if vals.size == 0:
                out[i, j] = 0
            else:
                color = int(vals[0])
                colored = np.count_nonzero(block == color)
                zeros = np.count_nonzero(block == 0)
                out[i, j] = color if colored > zeros else 0

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = input_grid
    h, w = grid.shape
    n = 3
    bh, bw = h // n, w // n

    # Determine occupied 3x3 block positions
    occ = np.zeros((bh, bw), dtype=bool)
    for i in range(bh):
        for j in range(bw):
            block = grid[i*n:(i+1)*n, j*n:(j+1)*n]
            occ[i, j] = np.any(block != 0)

    # Find a reference occupied block with the most filled cells
    best = None
    best_count = -1
    for i in range(bh):
        for j in range(bw):
            if occ[i, j]:
                cnt = np.count_nonzero(grid[i*n:(i+1)*n, j*n:(j+1)*n] != 0)
                if cnt > best_count:
                    best_count = cnt
                    best = (i, j)

    if best is None:
        return np.zeros((9, 9), dtype=int)

    bi, bj = best
    ref = grid[bi*n:(bi+1)*n, bj*n:(bj+1)*n]
    mask = (ref != 0).astype(int)

    out = np.zeros((9, 9), dtype=int)
    for i in range(bh):
        for j in range(bw):
            if occ[i, j]:
                out[i*n:(i+1)*n, j*n:(j+1)*n] = mask * 5

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    out = np.zeros_like(grid)

    # Find the non-zero template within the top-left 3x3 block
    template = grid[:3, :3]

    # Repeat the template across all 3x3 block positions
    for br in range(0, h, 3):
        for bc in range(0, w, 3):
            for r in range(3):
                for c in range(3):
                    if br + r < h and bc + c < w and template[r, c] != 0:
                        out[br + r, bc + c] = template[r, c]
    return out

