def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    for i in range(h - 1):
        for j in range(w - 1):
            v = grid[i, j]
            if v != 0 and grid[i, j + 1] == v and grid[i + 1, j] == v and grid[i + 1, j + 1] == v:
                grid[i, j] = 1
                grid[i, j + 1] = 2
                grid[i + 1, j] = 3
                grid[i + 1, j + 1] = 4
    return grid

