def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    H, W = grid.shape
    cell = 3
    nr, nc = H // cell, W // cell

    out = np.zeros((H * cell, W * cell), dtype=int)

    for br in range(nr):
        for bc in range(nc):
            block = grid[br * cell:(br + 1) * cell, bc * cell:(bc + 1) * cell]
            vals = block[block != 0]
            if vals.size == 0:
                continue
            color = int(vals[0])

            for r in range(cell):
                for c in range(cell):
                    if block[r, c] != 0:
                        rr = br * cell * cell + r * cell
                        cc = bc * cell * cell + c * cell
                        out[rr:rr + cell, cc:cc + cell] = color

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    out = g.copy()
    H, W = g.shape

    color = None
    for c in range(1, 10):
        if np.any(g == c):
            color = c
            break
    if color is None:
        return out

    mask = g == color
    rows = np.where(mask.any(axis=1))[0]
    cols = np.where(mask.any(axis=0))[0]
    if len(rows) == 0 or len(cols) == 0:
        return out

    # Find connected components of the target color using 4-neighborhood
    visited = np.zeros_like(mask, dtype=bool)
    comps = []

    for r in range(H):
        for c in range(W):
            if mask[r, c] and not visited[r, c]:
                stack = [(r, c)]
                visited[r, c] = True
                pts = []
                while stack:
                    x, y = stack.pop()
                    pts.append((x, y))
                    for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nx, ny = x + dx, y + dy
                        if 0 <= nx < H and 0 <= ny < W and mask[nx, ny] and not visited[nx, ny]:
                            visited[nx, ny] = True
                            stack.append((nx, ny))
                comps.append(pts)

    for pts in comps:
        rs = np.array([p[0] for p in pts])
        cs = np.array([p[1] for p in pts])
        r0, r1 = rs.min(), rs.max()
        c0, c1 = cs.min(), cs.max()

        # marker is the unique cell in the component that differs from the rectangle color
        # infer marker color as the non-target color inside the bounding box
        bbox = g[r0:r1 + 1, c0:c1 + 1]
        marker_positions = np.argwhere((bbox != color) & (bbox != 0))
        if marker_positions.size == 0:
            continue
        mr, mc = marker_positions[0]
        mr += r0
        mc += c0

        h = r1 - r0 + 1
        w = c1 - c0 + 1

        # Determine orientation by shape: if wider than tall, extend vertically; else horizontally.
        # Direction depends on whether the component is in upper/lower or left/right half of canvas.
        if h >= w:
            # vertical ray
            if mr < H / 2:
                rr = range(mr, H)
            else:
                rr = range(mr, -1, -1)
            for r in rr:
                if g[r, mc] == 0 or g[r, mc] == color:
                    out[r, mc] = color
                else:
                    break
        else:
            # horizontal ray
            if mc < W / 2:
                cc = range(mc, W)
            else:
                cc = range(mc, -1, -1)
            for c in cc:
                if g[mr, c] == 0 or g[mr, c] == color:
                    out[mr, c] = color
                else:
                    break

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    out = np.zeros((h, w), dtype=int)

    visited = np.zeros((h, w), dtype=bool)

    for r in range(h):
        for c in range(w):
            if grid[r, c] == 0 or visited[r, c]:
                continue

            color = grid[r, c]

            # Find maximal rectangle of same color starting at (r, c)
            rr = r
            while rr < h and grid[rr, c] == color:
                rr += 1
            cc = c
            while cc < w and grid[r, cc] == color:
                cc += 1

            # Determine rectangle bounds by expanding until color changes
            r2 = r
            while r2 < h and np.all(grid[r2, c:cc] == color):
                r2 += 1
            c2 = c
            while c2 < w and np.all(grid[r:r2, c2] == color):
                c2 += 1

            # Mark visited
            visited[r:r2, c:c2] = True

            hh = r2 - r
            ww = c2 - c

            for i in range(hh):
                for j in range(ww):
                    if i == 0 or i == hh - 1 or j == 0 or j == ww - 1:
                        if (i == 0 or i == hh - 1) and (j == 0 or j == ww - 1):
                            out[r + i, c + j] = 1
                        else:
                            out[r + i, c + j] = 4
                    else:
                        out[r + i, c + j] = 2

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    colored_rows = np.where(np.any(grid != 0, axis=1))[0]
    if len(colored_rows) == 0:
        return grid

    bottom = colored_rows[-1]
    if bottom == 0:
        return grid

    above = bottom - 1

    for c in range(w):
        val = grid[above, c]
        if val == 0:
            continue
        for nc in (c - 1, c + 1):
            if 0 <= nc < w and grid[above - 1, nc] == 0:
                grid[above - 1, nc] = val

    return grid

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    n, m = grid.shape

    visited = np.zeros_like(grid, dtype=bool)
    components = []

    for i in range(n):
        for j in range(m):
            if grid[i, j] == 5 and not visited[i, j]:
                stack = [(i, j)]
                visited[i, j] = True
                cells = []
                while stack:
                    x, y = stack.pop()
                    cells.append((x, y))
                    for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nx, ny = x + dx, y + dy
                        if 0 <= nx < n and 0 <= ny < m and grid[nx, ny] == 5 and not visited[nx, ny]:
                            visited[nx, ny] = True
                            stack.append((nx, ny))
                components.append(cells)

    def bbox(cells):
        xs = [x for x, _ in cells]
        ys = [y for _, y in cells]
        return min(xs), max(xs), min(ys), max(ys)

    # Map interior size to color based on examples:
    # 1x1 -> 6, 2x2 -> 7, 3x3 -> 8
    size_to_color = {1: 6, 2: 7, 3: 8}

    for cells in components:
        r0, r1, c0, c1 = bbox(cells)
        h = r1 - r0 + 1
        w = c1 - c0 + 1
        if h == w and h >= 3:
            interior = h - 2
            color = size_to_color.get(interior)
            if color is not None:
                grid[r0 + 1:r1, c0 + 1:c1] = color

    return grid

