import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape

    # Find seed cells: cells whose color differs from at least one 4-neighbor.
    seeds = []
    for r in range(h):
        for c in range(w):
            v = g[r, c]
            diff = False
            if r > 0 and g[r - 1, c] != v:
                diff = True
            if r + 1 < h and g[r + 1, c] != v:
                diff = True
            if c > 0 and g[r, c - 1] != v:
                diff = True
            if c + 1 < w and g[r, c + 1] != v:
                diff = True
            if diff:
                seeds.append((r, c, v))

    out = np.array(input_grid, copy=True)

    # Paint each seed's diagonal path to the nearest corner of the grid.
    # If a cell is already painted by an earlier seed, keep it unchanged.
    for r, c, v in seeds:
        corners = [(0, 0), (0, w - 1), (h - 1, 0), (h - 1, w - 1)]
        dists = [abs(r - rr) + abs(c - cc) for rr, cc in corners]
        min_d = min(dists)
        # Deterministic tie-breaking by corner order.
        rr, cc = corners[dists.index(min_d)]

        dr = 0 if rr == r else (1 if rr > r else -1)
        dc = 0 if cc == c else (1 if cc > c else -1)

        cr, cc2 = r, c
        while True:
            if out[cr, cc2] == input_grid[cr, cc2]:
                out[cr, cc2] = v
            if (cr, cc2) == (rr, cc):
                break
            cr += dr
            cc2 += dc

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    # Find the 2x2 block color and its bounding box
    colors, counts = np.unique(grid[grid != 0], return_counts=True)
    block_color = None
    block_rows = block_cols = None

    for c in colors:
        pos = np.argwhere(grid == c)
        if len(pos) == 4:
            rs = sorted(set(pos[:, 0].tolist()))
            cs = sorted(set(pos[:, 1].tolist()))
            if len(rs) == 2 and len(cs) == 2 and rs[1] == rs[0] + 1 and cs[1] == cs[0] + 1:
                block_color = c
                block_rows = rs
                block_cols = cs
                break

    if block_color is None:
        return grid

    r1, r2 = block_rows
    c1, c2 = block_cols

    # Preserve the block
    grid[r1:r2 + 1, c1:c2 + 1] = block_color

    # Draw lines from isolated colored points toward the block
    nonzero_positions = np.argwhere(input_grid != 0)
    for r, c in nonzero_positions:
        color = input_grid[r, c]
        if color == block_color and r1 <= r <= r2 and c1 <= c <= c2:
            continue

        # Same row as block: draw horizontally toward the block
        if r == r1 or r == r2:
            if c < c1:
                grid[r, c:c1] = color
            elif c > c2:
                grid[r, c2 + 1:c + 1] = color

        # Same column as block: draw vertically toward the block
        elif c == c1 or c == c2:
            if r < r1:
                grid[r:r1, c] = color
            elif r > r2:
                grid[r2 + 1:r + 1, c] = color

        # If point is aligned with the block's row/column range, extend to nearest edge
        else:
            if r < r1 and c1 <= c <= c2:
                grid[r:r1, c] = color
            elif r > r2 and c1 <= c <= c2:
                grid[r2 + 1:r + 1, c] = color
            elif c < c1 and r1 <= r <= r2:
                grid[r, c:c1] = color
            elif c > c2 and r1 <= r <= r2:
                grid[r, c2 + 1:c + 1] = color

    return grid

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    # Find the bottom-most row containing any non-zero value.
    nonzero_rows = np.where(np.any(grid != 0, axis=1))[0]
    if len(nonzero_rows) == 0:
        return grid
    bottom = nonzero_rows[-1]

    # Find the top of the repeating band by scanning upward until rows become all zero.
    top = bottom
    while top > 0 and np.any(grid[top - 1] != 0):
        top -= 1

    band = grid[top:bottom + 1]
    band_h = band.shape[0]

    # Determine the horizontal period from the non-zero structure in the band.
    # Use the smallest shift that reproduces the observed non-zero pattern.
    period = None
    for p in range(1, w):
        ok = True
        for r in range(band_h):
            row = band[r]
            nz = np.where(row != 0)[0]
            if len(nz) == 0:
                continue
            # Check that every non-zero cell matches a cell shifted by p where possible.
            for c in nz:
                if c - p >= 0 and row[c - p] != 0 and row[c - p] != row[c]:
                    ok = False
                    break
            if not ok:
                break
        if ok:
            period = p
            break

    if period is None:
        # Fallback: infer from the leftmost non-zero block width.
        nz_cols = np.where(np.any(band != 0, axis=0))[0]
        if len(nz_cols) == 0:
            return grid
        period = nz_cols[-1] - nz_cols[0] + 1

    # Extend the pattern rightward across the full width by copying the observed band.
    out = np.array(grid, copy=True)
    for c in range(w):
        src_c = c % period
        if src_c < band.shape[1]:
            out[top:bottom + 1, c] = band[:, src_c]
        else:
            out[top:bottom + 1, c] = 0

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    top = grid[0]
    marker_cols = [c for c in range(w) if top[c] != 0]

    # Determine contiguous non-zero blocks in the grid below the top row.
    visited = np.zeros((h, w), dtype=bool)

    def neighbors(r, c):
        if r > 0:
            yield r - 1, c
        if r + 1 < h:
            yield r + 1, c
        if c > 0:
            yield r, c - 1
        if c + 1 < w:
            yield r, c + 1

    for r in range(1, h):
        for c in range(w):
            if grid[r, c] == 0 or visited[r, c]:
                continue

            color = grid[r, c]
            stack = [(r, c)]
            visited[r, c] = True
            cells = []

            while stack:
                cr, cc = stack.pop()
                cells.append((cr, cc))
                for nr, nc in neighbors(cr, cc):
                    if not visited[nr, nc] and grid[nr, nc] == color:
                        visited[nr, nc] = True
                        stack.append((nr, nc))

            rows = [x for x, y in cells]
            cols = [y for x, y in cells]
            r0, r1 = min(rows), max(rows)
            c0, c1 = min(cols), max(cols)

            # Find the top-row marker whose column lies within the block's horizontal span.
            chosen_color = None
            for mc in marker_cols:
                if c0 <= mc <= c1:
                    chosen_color = top[mc]
                    break

            if chosen_color is None:
                # Fallback: choose the nearest marker column to the block center.
                center = (c0 + c1) / 2.0
                mc = min(marker_cols, key=lambda x: abs(x - center))
                chosen_color = top[mc]

            # Recolor the entire connected block.
            for rr, cc in cells:
                grid[rr, cc] = chosen_color

    return grid

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = input_grid
    h, w = g.shape

    # Find the dominant non-zero color (background of the larger canvas)
    vals, counts = np.unique(g[g != 0], return_counts=True)
    bg = vals[np.argmax(counts)] if len(vals) else 0

    # Determine whether the grid is split horizontally or vertically by bg separation
    row_bg = np.array([np.all(row == bg) for row in g])
    col_bg = np.array([np.all(g[:, j] == bg) for j in range(w)])

    # Prefer horizontal split if there is a full bg row separating content
    if np.any(row_bg):
        rows = np.where(~row_bg)[0]
        if len(rows) == 0:
            return np.zeros((0, 0), dtype=int)
        top, bottom = rows[0], rows[-1]
        # Extract the non-bg content region
        sub = g[top:bottom + 1, :]
        # Remove all-bg columns
        keep_cols = np.where(~np.all(sub == bg, axis=0))[0]
        if len(keep_cols) == 0:
            return np.zeros((0, 0), dtype=int)
        sub = sub[:, keep_cols]
        # If there are multiple separated blocks vertically, keep only the non-bg rows
        keep_rows = np.where(~np.all(sub == bg, axis=1))[0]
        if len(keep_rows) == 0:
            return np.zeros((0, 0), dtype=int)
        return sub[keep_rows[:, None], np.arange(sub.shape[1])]

    # Otherwise, use vertical split
    cols = np.where(~col_bg)[0]
    if len(cols) == 0:
        return np.zeros((0, 0), dtype=int)
    left, right = cols[0], cols[-1]
    sub = g[:, left:right + 1]
    keep_rows = np.where(~np.all(sub == bg, axis=1))[0]
    if len(keep_rows) == 0:
        return np.zeros((0, 0), dtype=int)
    sub = sub[keep_rows, :]
    keep_cols = np.where(~np.all(sub == bg, axis=0))[0]
    if len(keep_cols) == 0:
        return np.zeros((0, 0), dtype=int)
    return sub[:, keep_cols]

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    n, m = grid.shape
    visited = np.zeros((n, m), dtype=bool)

    for r in range(n):
        for c in range(m):
            if grid[r, c] == 0 and not visited[r, c]:
                stack = [(r, c)]
                comp = []
                visited[r, c] = True
                while stack:
                    x, y = stack.pop()
                    comp.append((x, y))
                    for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nx, ny = x + dx, y + dy
                        if 0 <= nx < n and 0 <= ny < m and grid[nx, ny] == 0 and not visited[nx, ny]:
                            visited[nx, ny] = True
                            stack.append((nx, ny))
                color = len(comp)
                for x, y in comp:
                    grid[x, y] = color
    return grid

