def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    h, w = input_grid.shape
    out = np.zeros((h // 2, w // 2), dtype=input_grid.dtype)
    for i in range(0, h, 2):
        for j in range(0, w, 2):
            block = input_grid[i:i+2, j:j+2]
            vals = block[block != 0]
            if vals.size:
                out[i // 2, j // 2] = vals[0]
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    out = np.array(grid, copy=True)

    # Find all 2x2 non-zero objects by scanning for top-left corners
    for r in range(h - 1):
        for c in range(w - 1):
            block = grid[r:r+2, c:c+2]
            if np.all(block != 0):
                colors = set(int(x) for x in block.flatten())
                count = len(colors)
                # Fill downward with green (3), starting just below the object
                for k in range(count):
                    rr = r + 2 + k
                    if rr < h:
                        out[rr, c:c+2] = 3
    return out
